items = _items

run_id = ""
symbols_ok = 0
symbols_error = 0
ai_calls = 0
vectors_written = 0
errors = []

for it in items:
    d = it.get("json", {}) or {}

    if not run_id:
        run_id = str(d.get("run_id", "") or "")

