        out["h1_indicators"] = h1_ind
        out["d1_indicators"] = d1_ind
        out["h1_signal"] = h1_sig
        out["d1_signal"] = d1_sig
        out["h1_freshness"] = h1_freshness
        out["d1_freshness"] = d1_freshness
        out["_status"] = "ok"
        results.append({"json": out})

